'use client';import { useParams,useRouter } from 'next/navigation';import { useErpData } from '@/components/erp/useErpData';import { PageHeader, SubmitButton } from '@/components/erp/shared';import { FormEvent,useEffect,useState } from 'react';import { Input } from '@/components/ui/input';import toast from 'react-hot-toast';import { formatCurrency } from '@/lib/utils';
export default function VendorDetail(){const {id}=useParams<{id:string}>();const {data}=useErpData();const router=useRouter();const v=data?.sellers?.find((x:any)=>x.id===id);const sales=(data?.sales||[]).filter((s:any)=>s.sellerId===id);const [f,setF]=useState<any>(null);const [loading,setLoading]=useState(false);useEffect(()=>{if(v)setF({...v,commissionRate:String(v.commissionRate||0)});},[v]);if(!f)return <div>Carregando...</div>;const save=async(e:FormEvent)=>{e.preventDefault();setLoading(true);const r=await fetch(`/api/v1/erp/sellers/${id}`,{method:'PATCH',headers:{'Content-Type':'application/json'},body:JSON.stringify({...f,commissionRate:Number(f.commissionRate)})});setLoading(false);if(!r.ok)return toast.error('Erro');toast.success('Vendedor atualizado');router.push('/dashboard/vendors');};const total=sales.reduce((a:number,b:any)=>a+(b.total-b.discount+b.freight),0);
return <div className='space-y-4'><PageHeader title={`Editar vendedor · ${f.name}`} subtitle={`Total vendido: ${formatCurrency(total)} | Comissão estimada: ${formatCurrency(total*Number(f.commissionRate||0)/100)}`}/><form onSubmit={save} className='bg-white border rounded p-4 space-y-2'><Input value={f.name} onChange={e=>setF({...f,name:e.target.value})}/><Input value={f.email||''} onChange={e=>setF({...f,email:e.target.value})}/><Input value={f.phone||''} onChange={e=>setF({...f,phone:e.target.value})}/><Input type='number' step='0.01' value={f.commissionRate} onChange={e=>setF({...f,commissionRate:e.target.value})}/><Input value={f.notes||''} onChange={e=>setF({...f,notes:e.target.value})}/><SubmitButton loading={loading}>Salvar alterações</SubmitButton></form></div>}
